@Entity('eoi_batch_vouchers')
@Index(['voucherId', 'stage'], {
  unique: true,
})
export class EoiBatchVoucher {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column({
    name: 'batch_id',
    type: 'varchar',
  })
  batchId: string;

  @ManyToOne(() => EoiBatch, {
    onDelete: 'CASCADE',
  })
  @JoinColumn({ name: 'batch_id' })
  batch: EoiBatch;

  @Column({
    name: 'slot_id',
    type: 'varchar',
  })
  slotId: string;

  @ManyToOne(() => EoiBatchSlot, (slot) => slot.batchVouchers)
  @JoinColumn({ name: 'slot_id' })
  slot: EoiBatchSlot;

  @Column({
    name: 'voucher_id',
    type: 'int',
  })
  voucherId: number;

  @ManyToOne(() => VoucherForm)
  @JoinColumn({ name: 'voucher_id' })
  voucher: VoucherForm;

  /**
   * Business uniqueness scope.
   * Same voucher can participate
   * in different stages.
   */
  @Column({
    type: 'enum',
    enum: BatchStage,
  })
  stage: BatchStage;

  /**
   * Snapshot fields
   */

  @Column({
    name: 'customer_name',
    type: 'varchar',
    length: 255,
    nullable: true,
  })
  customerName?: string;

  @Column({
    name: 'email',
    type: 'varchar',
    length: 255,
    nullable: true,
  })
  email?: string;

  @Column({
    name: 'phone',
    type: 'varchar',
    length: 20,
    nullable: true,
  })
  phone?: string;

  @CreateDateColumn({
    name: 'assigned_at',
  })
  assignedAt: Date;

  @Column({
    type: 'enum',
    enum: BatchVoucherStatus,
    default: BatchVoucherStatus.INVITED,
  })
  status: BatchVoucherStatus;

  @Column({ type: 'text', nullable: true, name: 'comments' })
  comments: string;
}

